parameters.jsCode:
let rawOutput = $json.output;

// Aseguramos que sea string
rawOutput = String(rawOutput).trim();

// Eliminamos bloques tipo ```json ... ```
rawOutput = rawOutput
  .replace(/```(json)?/gi, "") // elimina ```json o ``` 
  .replace(/```/g, "")         // elimina ``` finales
  .trim();

// Eliminamos caracteres de escape (\n, \t, etc.)
rawOutput = rawOutput
  .replace(/\\n/g, "")
  .replace(/\\t/g, "")
  .replace(/\r/g, "")
  .trim();

// A veces vienen comillas escapadas dentro del texto; las corregimos si es necesario
if (rawOutput.startsWith('"') && rawOutput.endsWith('"')) {
  rawOutput = rawOutput.slice(1, -1);
}

// Intentamos parsear
let parsed;
try {
  parsed = JSON.parse(rawOutput);

  return {
    lead_status: parsed.etiqueta,
    bot_status: parsed.estado
  };

} catch (error) {
  throw new Error("Error al parsear el JSON: " + error.message + "\nContenido limpio: " + rawOutput);
}

